    def man(ax, ay, bx, by):
        dx = ax - bx
        if dx < 0:
            dx = -dx
        dy = ay - by
        if dy < 0:
            dy = -dy
        return dx + dy

    def ok(x, y):
        return 0 <= x < w and 0 <= y < h and (x, y) not in obstacles

    moves = [(0, 0), (0, -1), (-1, 0), (1, 0), (0, 1)]
    if not resources:
        for dx, dy in moves:
            nx, ny = sx + dx, sy + dy
            if ok(nx, ny):
                return [dx, dy]
        return [0, 0]

    best_move = (0, 0)
    best_val = None
    for dx, dy in moves:
        nx, ny = sx + dx, sy + dy
        if not ok(nx, ny):
            continue
        cur_best_diff = 10**9
        cur_best_self = 10**9
        for rx, ry in resources:
            ds = man(nx, ny, rx, ry)
            do = man(ox, oy, rx, ry)
            diff = ds - do  # smaller => we are relatively closer
            if diff < cur_best_diff or (diff == cur_best_diff and ds < cur_best_self):
                cur_best_diff = diff
                cur_best_self = ds
        val = (cur_best_diff, cur_best_self)
        if best_val is None or val < best_val:
            best_val = val
            best_move = (dx, dy)
    return [best_move[0], best_move[1]]
